sql:
SELECT AVG(execution_time) AS average_execution_time
FROM trial_executions
WHERE hardware_used = 'NVIDIA GeForce RTX 3080';

SELECT execution_time, hardware_used
FROM trial_executions
WHERE execution_status = 'success';

SELECT AVG(execution_time) AS average_execution_time
FROM trial_executions
WHERE hardware_used = 'NVIDIA GeForce RTX 3080' AND execution_status = 'success';

external_knowledge:
- 'Experiment champions' refers to the experiments with the highest average validation accuracy.; 
- 'Coaches' refers to the users who created the experiments, represented by their usernames.; 
- 'The final whistle blew' refers to the point when the experiment status is 'COMPLETED'.; 
- 'Prowess' refers to the average validation accuracy achieved by each experiment.
